import mongoose from 'mongoose';
import dotenv from 'dotenv';
import path from 'path';
import { fileURLToPath } from 'url';

const __dirname = path.dirname(fileURLToPath(import.meta.url));
dotenv.config({ path: path.resolve(__dirname, '../.env.local') });
dotenv.config({ path: path.resolve(__dirname, '../.env') });

const MONGO_URI = process.env.MONGO_URI;
if (!MONGO_URI) { console.error('MONGO_URI not found'); process.exit(1); }

const examCategorySchema = new mongoose.Schema({
  name: { type: String, required: true, trim: true },
  type: { type: String, enum: ['Central', 'State'], required: true },
  description: { type: String, trim: true }
}, { timestamps: true });

const examSchema = new mongoose.Schema({
  category: { type: mongoose.Schema.Types.ObjectId, ref: 'ExamCategory', required: true },
  name: { type: String, required: true, trim: true },
  code: { type: String, required: true, uppercase: true, trim: true },
  description: { type: String, trim: true },
  isActive: { type: Boolean, default: true },
  logo: { type: String }
}, { timestamps: true });

const examPatternSchema = new mongoose.Schema({
  exam: { type: mongoose.Schema.Types.ObjectId, ref: 'Exam', required: true },
  title: { type: String, required: true, trim: true },
  duration: { type: Number, required: true, min: 1 },
  totalMarks: { type: Number, required: true, min: 0 },
  negativeMarking: { type: Number, default: 0, min: 0 },
  sections: [{
    name: { type: String, required: true, trim: true },
    totalQuestions: { type: Number, required: true, min: 1 },
    marksPerQuestion: { type: Number, required: true, min: 0 },
    negativePerQuestion: { type: Number, default: 0, min: 0 },
    sectionDuration: { type: Number, min: 0 }
  }]
}, { timestamps: true });

const practiceTestSchema = new mongoose.Schema({
  examPattern: { type: mongoose.Schema.Types.ObjectId, ref: 'ExamPattern', required: true },
  title: { type: String, required: true, trim: true },
  slug: { type: String, lowercase: true, trim: true },
  totalMarks: { type: Number, required: true, min: 0 },
  duration: { type: Number, required: true, min: 1 },
  accessLevel: { type: String, enum: ['FREE', 'PRO'], default: 'FREE' },
  isPYQ: { type: Boolean, default: false },
  pyqYear: { type: Number, default: null },
  pyqShift: { type: String, default: null, trim: true },
  pyqExamName: { type: String, default: null, trim: true },
  publishedAt: { type: Date, default: Date.now },
  questions: [{
    questionText: { type: String, required: true },
    questionImage: { type: String, default: '' },
    options: [{ type: String, required: true }],
    optionImages: [{ type: String, default: '' }],
    correctAnswerIndex: { type: Number, required: true, min: 0 },
    explanation: { type: String, trim: true },
    section: { type: String, required: true, trim: true },
    tags: [{ type: String, trim: true }],
    difficulty: { type: String, enum: ['easy', 'medium', 'hard', 'mixed'], default: 'medium' }
  }]
}, { timestamps: true });

const ExamCategory = mongoose.models.ExamCategory || mongoose.model('ExamCategory', examCategorySchema);
const Exam = mongoose.models.Exam || mongoose.model('Exam', examSchema);
const ExamPattern = mongoose.models.ExamPattern || mongoose.model('ExamPattern', examPatternSchema);
const PracticeTest = mongoose.models.PracticeTest || mongoose.model('PracticeTest', practiceTestSchema);

const REA = 'General Intelligence';
const ENG = 'English Language';
const QA  = 'Quantitative Aptitude';
const GA  = 'General Awareness';

const KEY = [4, 4, 2, 3, 3, 3, 3, 3, 3, 3, 4, 2, 1, 3, 3, 1, 4, 1, 2, 2, 1, 3, 1, 1, 1, 1, 2, 3, 3, 1, 1, 2, 3, 2, 3, 2, 2, 2, 2, 2, 1, 2, 2, 2, 1, 1, 2, 3, 2, 1, 3, 1, 2, 3, 2, 2, 4, 4, 3, 2, 1, 2, 1, 3, 1, 3, 4, 2, 2, 1, 3, 1, 1, 4, 1, 4, 1, 1, 4, 2, 1, 1, 4, 3, 2, 2, 2, 1, 1, 1, 3, 3, 1, 1, 1, 3, 3, 2, 3, 1];
if (KEY.length !== 100) { console.error(`KEY length ${KEY.length}`); process.exit(1); }

const RAW = [
  { s: `General Intelligence`, q: `Which word is different from the rest?`, o: [`Tiger`, `Lion`, `Leopard`, `Cow`], e: `Cow is a domestic herbivorous animal. Created FromSDoa,tCeow is odd one out. Created To Date Thus, correct option is (d). IDQ.2 WhicIhDnumber doesTnIoTtLbEelong toLtAheNsGeUt?AGE SUBJECT CATEGORY EXAMS MARKS (MINS) AT AT PA A. 125 SSC Selection Hindi FULL- SSC SSC 200 60 Fri, Mar Tue, Jan V Selection 20, 2026, 27, 2026, C. 343 (Matriculation) D. 256 Similar Paper Post 11:44:31 21:55:09 (Held on 25 Answer: D Jul 2025 S1) Sol: N ow, we check each options. 53= 125 Post Selection 20, 2026, 27, 2026, Option (c): 343 (Held on 25 73= 343 Jul 2025 S1) Option (d): 256 162= 256 So, 256 is odd one out. Thus, correct option is (d).` },
  { s: `General Intelligence`, q: `Find the odd one.`, o: [`125`, `216`, `343`, `256`], e: `125 = 5³, 216 = 6³, 343 = 7³ are perfect cubes. 256 = 2⁸ (not a perfect cube). Option D.` },
  { s: `General Intelligence`, q: `Complete the series: AX, BY, CZ, ___`, o: [`DW`, `DA`, `DX`, `EW`], e: `Given: AX, BY, CZ, ___ Logic: Letters are increasing + 1 place. A + 1 = B, B + 1 = C, C + 1 = D X + 1 = Y, Y + 1 = Z, Z + 1 = A So, the missing term is DA. Thus, correct option is (b).` },
  { s: `General Intelligence`, q: `Find the missing number in the series: 1, 8, 27, 64, ___`, o: [`100`, `121`, `125`, `144`], e: `Given: 1, 8, 27, 64, ___ Logic: Numbers are increasing perfect cube of natural number. 1 = 13 8 = 23 27 = 33 64 = 43 Next number = 5 53= 125 So, the missing term is 125. Thus, correct option is (c).` },
  { s: `General Intelligence`, q: `In a coded operation, 6 3 = 6, 12 4 = 8, what is 10 5?`, o: [`6`, `7`, `8`, `9`], e: `Given: 6 3 = 6, 12 4 = 8 Logic: (1st number ÷ 2nd number) + (2nd number + 1) = 3rd number For, 6 3 = 6 (6 ÷ 3) + (3 + 1) = 2 + 4 = 6 For, 12 4 = 8 (12 ÷ 4) + (4 + 1) = 3 + 5 = 8 Similarly, 10 5? (10 ÷ 5) + (5 + 1) = 2 + 6 = 8 Thus, correct option is (c).` },
  { s: `General Intelligence`, q: `If there is a fire in a building, what is the safest first action?`, o: [`Hide inside`, `Call friends`, `Use the nearest safe exit`, `Panic and run randomly`], e: `Given: If there is a fire in a building. Explanation: In a fire emergency, the safest first action is to stay calm and use the nearest safe exit to evacuate the building quickly and safely. So, Use the nearest safe exit is the safest first action. Thus, correct option is (c).` },
  { s: `General Intelligence`, q: `What comes next in the series: B, H, N, T, ___?`, o: [`X`, `Y`, `Z`, `V`], e: `Given: B, H, N, T, ___? Logic: Letters are increasing + 6 place. B+6=H H+6=N N+6=T T+6=Z So, the missing term is Z. Thus, correct option is (c).` },
  { s: `General Intelligence`, q: `A factory manager is asked to increase production by ignoring quality checks. What is the best decision?`, o: [`Ignore quality for speed`, `Reduce safety standards`, `Maintain quality while optimizing process`, `Stop production completely`], e: `Given: A factory manager is asked to increase production by ignoring quality checks. Explanation: Ignoring quality or safety can cause serious long-term problems. The best decision is to maintain quality standards and look for ways to optimize the production process to improve output responsibly. So, Maintain quality while optimizing process is the best decision. Thus, correct option is (c).` },
  { s: `General Intelligence`, q: `You find an important document lying in a public place. What should you do?`, o: [`Ignore it`, `Take it home`, `Try to return it to the owner`, `Destroy it`], e: `Given: You find an important document lying in a public place. Explanation: Returning the document to its owner is the most ethical and responsible action, ensuring it reaches the right person safely. So, Try to return it to the owner should you do. Thus, correct option is (c).` },
  { s: `General Intelligence`, q: `If 7 is to 49, then 12 is to ___?`, o: [`120`, `132`, `144`, `156`], e: `Given: If 7 is to 49, then 12 is to ___? Logic: 1st number2= 2nd number 72= 49 Similarly, 122= 144 Thus, correct option is (c).` },
  { s: `General Intelligence`, q: `Find the word that does not match the others.`, o: [`Chair`, `Table`, `Bed`, `Plate`], e: `Chair, Table and Bed are pieces of furniture. Plate is a utensil, not furniture. So, Plate is odd one out.. Thus, correct option is (d).` },
  { s: `General Intelligence`, q: `If = 5 and = 2, what is the value of ( × ) - ?`, o: [`6`, `8`, `10`, `12`], e: `Given: = 5 and = 2 Expression: (( × ) - ) = ((5 × 2) - 2) = 10 - 2 =8 Thus, correct option is (b).` },
  { s: `General Intelligence`, q: `Complete the analogy: Book : Pages :: Tree : ___`, o: [`Leaves`, `Branch`, `Root`, `Fruit`], e: `Given: Book : Pages :: Tree : ___ A book is made up of pages. Similarly, A tree is made up of leaves. Thus, correct option is (a).` },
  { s: `General Intelligence`, q: `If 6 : 42, then 9 : ___?`, o: [`54`, `56`, `63`, `72`], e: `Given: If 6 : 42, then 9 : ___? Logic: 1st number × 7 = 2nd number For, 6 : 42 6 × 7 = 42 Similarly, 9 : ___? 9 × 7 = 63 Thus, correct option is (c).` },
  { s: `General Intelligence`, q: `You have a job interview tomorrow but are feeling tired. What should you do?`, o: [`Skip preparation`, `Stay up watching movies`, `Prepare lightly and rest well`, `Cancel the interview`], e: `Given: You have a job interview tomorrow but are feeling tired. Explanation: Getting adequate rest while doing light, focused preparation helps you stay fresh, confident, and perform your best in the interview. So, Prepare lightly and rest well should you do. Thus, correct option is (c).` },
  { s: `General Intelligence`, q: `Hand is to Write as Mouth is to ___?`, o: [`Speak`, `Eat`, `Taste`, `Smile`], e: `Given: Hand is to Write as Mouth is to ___? We use the hand to write. Similarly, We use the mouth to speak. Thus, correct option is (a).` },
  { s: `General Intelligence`, q: `Which number is different from the rest?`, o: [`9`, `16`, `25`, `27`], e: `Now, we check each options. Option (a): 9 32= 9 Option (b): 16 42= 16 Option (c): 25 52= 25 Option (d): 27 33= 27 So, 27 is odd one out. Thus, correct option is (d).` },
  { s: `General Intelligence`, q: `If P is the daughter of Q, and Q is the sister of R, how is P related to R?`, o: [`Niece`, `Mother`, `Sister`, `Cousin`], e: `Given: If P is the daughter of Q, and Q is the sister of R. From the given information blood relation diagram will be. So, P is niece of R. Thus, correct option is (a).` },
  { s: `General Intelligence`, q: `If 5 is to 25, then 9 is to ___?`, o: [`72`, `81`, `90`, `99`], e: `Given: If 5 is to 25, then 9 is to ___? Logic: 1st number2= 2nd number 52= 25 Similarly, 92= 81 Thus, correct option is (b).` },
  { s: `General Intelligence`, q: `If HARD is related to KDUG, then SOFT is related to ___?`, o: [`WTKG`, `VRIW`, `VQIT`, `WUHT`], e: `Given: If HARD is related to KDUG. Logic: Letters are increasing + 3 place. For, HARD - KDUG H + 3 = K, A + 3 = D, R + 3 = U, D + 3 = G Similarly, SOFT - ? S + 3 = V, O + 3 = R, F + 3 = I, T + 3 = W So, SOFT is related to VRIW. Thus, correct option is (b).` },
  { s: `General Intelligence`, q: `Identify the next term in the sequence: A2, C6, F12, ___ ?`, o: [`J20`, `I18`, `H16`, `K22`], e: `Given: A2, C6, F12, ___ ? Logic: Letters are increasing number from 2 and number are increasing even number from 4. For, letter A + 2 = C, C + 3 = F, F + 4 = J For, number 2 + 4 = 6, 6 + 6 = 12, 12 + 8 = 20 So, the missing term is J20. Thus, correct option is (a).` },
  { s: `General Intelligence`, q: `Identify the missing number: 2, 5, 10, 17, ___`, o: [`24`, `25`, `26`, `27`], e: `Given: 2, 5, 10, 17, ___ Logic: Numbers are increasing odd number from 3. 2+3=5 5 + 5 = 10 10 + 7 = 17 17 + 9 = 26 So, the missing term is 26. Thus, correct option is (c).` },
  { s: `General Intelligence`, q: `Engineer is to Factory as Doctor is to ___?`, o: [`Clinic`, `School`, `Court`, `Market`], e: `Given: Engineer is to Factory as Doctor is to ___? An engineer works in a factory. Similarly, A doctor works in a clinic. Thus, correct option is (a).` },
  { s: `General Intelligence`, q: `A shopkeeper marks an article 25% above cost price and allows a discount of 20%. What is the net change in price?`, o: [`No change`, `5% increase`, `5% decrease`, `10% increase`], e: `Given: A shopkeeper marks an article 25% above cost price and allows a discount of 20%. Solution: Let the cost price = 100. Marked price = (100 + 25% = 125) Discount = (20%) of 125 = (25) Selling price = (125 - 25 = 100) Selling Price = Cost Price. So, No change is the net change in price. Thus, correct option is (a).` },
  { s: `General Intelligence`, q: `PQRS : QPRS :: WXYZ : ___?`, o: [`XWYZ`, `WXZY`, `XWZY`, `YXWZ`], e: `Given: PQRS : QPRS :: WXYZ : ___? Logic: 1st two letters are interchanged and other are same. For, PQRS : QPRS PQRS = QPRS Similarly, WXYZ : ___? WXYZ = XWYZ Thus, correct option is (a).` },
  { s: `General Awareness`, q: `Which constitutional article guarantees the Right to Equality in India?`, o: [`Article 14`, `Article 19`, `Article 21`, `Article 32`], e: `The correct answer is (A) Article 14 Explanation: · Article 14 of the Indian Constitution states that the State shall not deny to any person equality before the law or the equal protection of the laws within the territory of India. · It is the first article under the Right to Equality (Articles 14-18). Information Booster: · The concept of 'Equality before Law' is of British origin, while 'Equal Protection of Laws' is taken from the American Constitution. Additional Knowledge: · Article 19 (Option B): Guarantees the Right to Freedom (speech, assembly, etc.). · Article 21 (Option C): Protection of Life and Personal Liberty. · Article 32 (Option D): Right to Constitutional Remedies.` },
  { s: `General Awareness`, q: `As per the Environment (Protection) Act, 1986, which of the following authorities has the power to take measures to protect and improve the environment in India?`, o: [`State Public Service Commission`, `Ministry of Environment, Forest and Climate Change`, `Election Commission of India`, `Finance Commission`], e: `The correct answer is (B) Ministry of Environment, Forest and Climate Change Explanation: · The Environment (Protection) Act, 1986 authorizes the Central Government (represented by the MoEFCC) to take all necessary measures for protecting and improving the quality of the environment. · This includes setting standards for emissions and discharges and managing hazardous substances. Information Booster: · This Act was enacted in the wake of the Bhopal Gas Tragedy under Article 253 of the Constitution. Additional Knowledge: · Election Commission (Option C): Handles the conduct of elections. · Finance Commission (Option D): Handles the distribution of financial resources between the Center and States.` },
  { s: `General Awareness`, q: `As per the Biological Diversity (Amendment) Act, 2023, which of the following activities does NOT require prior approval from the National Biodiversity Authority (NBA)?`, o: [`Transfer of research results to foreign companies`, `Applying for intellectual property rights based on biological resources obtained from India`, `Use of biological resources by Indian researchers for academic research within India`, `Access to biological resources by foreign individuals or companies`], e: `The correct answer is (C) Use of biological resources by Indian researchers for academic research within India Explanation: · The 2023 Amendment aims to simplify compliance for Indian researchers and practitioners of Indian systems of medicine. · Indian entities and researchers conducting research within India generally do not require prior NBA approval, though they may need to intimate State Biodiversity Boards. Information Booster: · The amendment also exempts Ayush practitioners and cultivated medicinal plants from the purview of 'access and benefit sharing' (ABS) requirements. Additional Knowledge: · Option A, B, and D: These still involve foreign elements or commercial IP rights which generally require NBA oversight to prevent bio-piracy.` },
  { s: `General Awareness`, q: `Which type of vegetation is mainly found in the Thar Desert region of India?`, o: [`Tropical evergreen forests`, `Temperate forests`, `Desert vegetation`, `Mangrove forests`], e: `The correct answer is (C) Desert vegetation Explanation: · The Thar Desert (Great Indian Desert) is characterized by arid conditions with low rainfall, leading to xerophytic vegetation. · This includes thorny bushes, shrubs, and trees like Khejri that can survive with minimal water. Information Booster: · Plants in this region often have deep roots, thick fleshy stems (succulents), and leaves reduced to spines to prevent water loss. Additional Knowledge: · Tropical evergreen (Option A): Found in Western Ghats and North-East India. · Mangrove (Option D): Found in coastal/deltaic regions like the Sundarbans.` },
  { s: `General Awareness`, q: `What term is used for organisms that produce their own food using sunlight in an ecosystem?`, o: [`Producers`, `Consumers`, `Decomposers`, `Parasites`], e: `The correct answer is (A) Producers Explanation: · Producers (also known as Autotrophs) are organisms like green plants and algae that use photosynthesis to convert sunlight into chemical energy. · They form the base of every food chain. Information Booster: · Photosynthesis requires carbon dioxide, water, and sunlight in the presence of chlorophyll. Additional Knowledge: · Consumers (Option B): Organisms that eat other organisms (Heterotrophs). · Decomposers (Option C): Organisms like fungi and bacteria that break down dead organic matter. · Parasites (Option D): Organisms that live on or in a host and get food at the host's expense.` },
  { s: `General Awareness`, q: `What remains constant during the boiling process of a pure liquid at constant pressure?`, o: [`Temperature`, `Density`, `Volume`, `Mass`], e: `The correct answer is (A) Temperature Explanation: · When a pure liquid boils at constant pressure, the heat supplied is used for the phase change (latent heat of vaporization) rather than increasing the kinetic energy of the molecules. · Therefore, the temperature remains constant at the boiling point until all the liquid has turned into gas. Information Booster: · The boiling point of water is 100°C at standard atmospheric pressure. Additional Knowledge: · Volume (Option C): Increases significantly as a liquid turns into gas. · Density (Option B): Decreases as the substance expands from liquid to gas.` },
  { s: `General Awareness`, q: `Which planet is known as the "Red Planet" in our solar system?`, o: [`Venus`, `Mars`, `Jupiter`, `Mercury`], e: `The correct answer is (B) Mars Explanation: · Mars is called the Red Planet because of the prevalence of iron oxide (rust) on its surface, which gives it a reddish appearance. · It is the fourth planet from the Sun. Information Booster: · Mars has the largest volcano in the solar system, Olympus Mons, and two moons: Phobos and Deimos. Additional Knowledge: · Venus (Option A): Known as the 'Morning Star' or 'Evening Star' and is the hottest planet. · Jupiter (Option C): The largest planet in our solar system. · Mercury (Option D): The smallest planet and closest to the Sun.` },
  { s: `General Awareness`, q: `Which Indian space mission was launched to study the Sun's outer atmosphere (corona)?`, o: [`Chandrayaan-3`, `Mangalyaan`, `Aditya-L1`, `Astrosat`], e: `The correct answer is (C) Aditya-L1 Explanation: · Aditya-L1 is India's first dedicated solar mission launched by ISRO in September 2023. · It is placed in a halo orbit around the Lagrange point 1 (L1) of the Sun-Earth system. Information Booster: · The mission carries seven payloads to observe the photosphere, chromosphere, and the outermost layers of the Sun (the corona). Additional Knowledge: · Chandrayaan-3 (Option A): India's third lunar mission to study the Moon's South Pole. · Mangalyaan (Option B): India's Mars Orbiter Mission (MOM). · Astrosat (Option D): India's first multi-wavelength space observatory.` },
  { s: `General Awareness`, q: `Which state hosted the Khelo India Youth Games 2023?`, o: [`Haryana`, `Madhya Pradesh`, `Gujarat`, `Tamil Nadu`], e: `The correct answer is (B) Madhya Pradesh Explanation: · The 5th edition of the Khelo India Youth Games was held in Madhya Pradesh in early 2023 across eight different cities. · Maharashtra topped the medal tally in this edition. Information Booster: · The mascot for the 2023 games was 'Asha' (a female cheetah) and 'Mowgli'. Additional Knowledge: · Tamil Nadu (Option D): Hosted the 6th edition of the Khelo India Youth Games in 2024.` },
  { s: `General Awareness`, q: `Which of the following is an example of monetary policy in India?`, o: [`Government spending on roads`, `Increasing income tax`, `Changing repo rate by RBI`, `Increasing subsidy on fertilizers`], e: `The correct answer is (C) Changing repo rate by RBI Explanation: · Monetary policy is the process by which the central bank (RBI) manages the supply of money and interest rates to achieve economic goals like inflation control. · Changing the Repo Rate (the rate at which RBI lends to banks) is a primary tool of monetary policy. Information Booster: · The Monetary Policy Committee (MPC) of the RBI meets bimonthly to decide these rates. Additional Knowledge: · Options A, B, and D are examples of Fiscal Policy, which is managed by the Government of India through taxes and spending.` },
  { s: `General Awareness`, q: `Which of the following organizations aims to promote economic cooperation among Southeast Asian nations?`, o: [`SAARC`, `ASEAN`, `BRICS`, `OPEC`], e: `The correct answer is (B) ASEAN Explanation: · ASEAN (Association of Southeast Asian Nations) was established in 1967 to accelerate economic growth, social progress, and cultural development in Southeast Asia. · It consists of 10 member states: Brunei, Cambodia, Indonesia, Laos, Malaysia, Myanmar, Philippines, Singapore, Thailand, and Vietnam. Information Booster: · The headquarters of ASEAN is located in Jakarta, Indonesia. Additional Knowledge: · SAARC (Option A): Focuses on South Asian nations. · BRICS (Option C): Group of major emerging economies (Brazil, Russia, India, China, South Africa). · OPEC (Option D): Organization of the Petroleum Exporting Countries.` },
  { s: `General Awareness`, q: `Under the Pradhan Mantri Awas Yojana (PMAY), the main objective is to provide:`, o: [`Free LPG connections`, `Affordable housing for all`, `Free health insurance`, `Free electricity connections`], e: `The correct answer is (B) Affordable housing for all Explanation: · Launched in 2015, PMAY aims to provide 'Housing for All' in urban and rural areas. · It provides financial assistance and interest subsidies to eligible beneficiaries to build or buy homes. Information Booster: · PMAY is divided into two parts: PMAY-Urban (PMAY-U) and PMAY-Gramin (PMAY-G). Additional Knowledge: · Ujjwala Yojana (Option A): Provides free LPG connections. · Saubhagya Scheme (Option D): Provides free electricity connections.` },
  { s: `General Awareness`, q: `Which of the following is NOT a component of emotional well-being?`, o: [`Self-confidence`, `Anxiety`, `Positive relationships`, `Life satisfaction`], e: `The correct answer is (B) Anxiety Explanation: · Emotional well-being refers to the ability to handle life's stresses and adapt to change and difficult times. · Anxiety is a state of distress and is considered a challenge to or a negative indicator of emotional well-being rather than a component of it. Information Booster: · Components of emotional health typically include resilience, self-esteem, and the ability to manage emotions effectively. Additional Knowledge: · Options A, C, and D are all positive traits or outcomes associated with high emotional well-being.` },
  { s: `General Awareness`, q: `Which of the following is a key feature of the Pradhan Mantri Mudra Yojana (PMMY)?`, o: [`Loans for large industries`, `Loans for small and micro enterprises`, `Loans for agriculture subsidies`, `Loans for foreign trade`], e: `The correct answer is (B) Loans for small and micro enterprises Explanation: · PMMY provides loans up to 10 lakh to non-corporate, non-farm small/micro enterprises. · These loans are classified as MUDRA loans and are given by Commercial Banks, RRBs, Small Finance Banks, MFIs, and NBFCs. Information Booster: · The scheme has three categories: Shishu (up to 50,000), Kishore (50,000 to 5 lakh), and Tarun (5 lakh to 10 lakh). Additional Knowledge: · Mudra stands for Micro Units Development & Refinance Agency Ltd.` },
  { s: `General Awareness`, q: `Which country joined BRICS as a new member in 2024?`, o: [`Argentina`, `Egypt`, `Japan`, `Germany`], e: `The correct answer is (B) Egypt Explanation: · Starting January 1, 2024, BRICS expanded its membership. Egypt, along with Ethiopia, Iran, and the United Arab Emirates, officially joined the group. · Saudi Arabia also participates but has yet to officially finalize its accession. Information Booster: · Argentina (Option A) was invited but declined to join after a change in its government leadership. Additional Knowledge: · The original BRIC was coined by Jim O'Neill; South Africa joined in 2010 to make it BRICS.` },
  { s: `General Awareness`, q: `Which Indian state has the second highest population according to the 2011 Census?`, o: [`Maharashtra`, `Bihar`, `West Bengal`, `Madhya Pradesh`], e: `The correct answer is (A) Maharashtra Explanation: · According to the 2011 Census, Uttar Pradesh is the most populous state in India. · Maharashtra ranks second, followed by Bihar (3rd) and West Bengal (4th). Information Booster: · Uttar Pradesh's population in 2011 was approximately 19.98 crore, while Maharashtra's was 11.24 crore. Additional Knowledge: · Bihar (Option B): Has the highest population density in India according to the 2011 Census.` },
  { s: `General Awareness`, q: `Under the Pradhan Mantri Fasal Bima Yojana (PMFBY), farmers are mainly provided:`, o: [`Free seeds`, `Crop insurance coverage`, `Free electricity`, `Subsidized fertilizers`], e: `The correct answer is (B) Crop insurance coverage Explanation: · Launched in 2016, PMFBY provides insurance coverage and financial support to farmers in the event of failure of any of the notified crops as a result of natural calamities, pests, and diseases. · It aims to stabilize the income of farmers to ensure their continuance in farming. Information Booster: · The premium paid by farmers is very low: 2% for Kharif, 1.5% for Rabi, and 5% for commercial/horticultural crops. Additional Knowledge: · PM-PRANAM (Option D): Encourages the use of bio-fertilizers and reduces subsidy on chemical fertilizers.` },
  { s: `General Awareness`, q: `What is the main objective of the Pradhan Mantri Jan Arogya Yojana (PM-JAY)?`, o: [`Providing free education`, `Providing health insurance coverage to poor families`, `Providing subsidized housing`, `Providing crop insurance to farmers`], e: `The correct answer is (B) Providing health insurance coverage to poor families Explanation: · PM-JAY (Ayushman Bharat) is the world's largest government-funded healthcare program. · It provides a health cover of 5 lakh per family per year for secondary and tertiary care hospitalization to over 12 crore poor and vulnerable families. Information Booster: · It is a completely cashless and paperless scheme at public and empanelled private hospitals. Additional Knowledge: · PMFBY (Option D): Provides crop insurance. · Samagra Shiksha (Option A): Focuses on free education.` },
  { s: `General Awareness`, q: `The Gandhara school of art flourished mainly during which period?`, o: [`Maurya period`, `Kushan period`, `Mughal period`, `Gupta period`], e: `The correct answer is (B) Kushan period Explanation: · The Gandhara school of art flourished during the reign of the Kushan empire, particularly under King Kanishka (1st century CE). · It is known for its Greco-Buddhist style, where Buddhist themes were depicted using Greek/Roman artistic techniques. Information Booster: · In Gandhara art, the Buddha was often shown with wavy hair, drapery resembling a Roman toga, and muscular features. Additional Knowledge: · Gupta period (Option D): Often called the 'Golden Age' of Indian art, known for the Mathura and Sarnath schools.` },
  { s: `General Awareness`, q: `Who wrote the famous book "My Experiments with Truth"?`, o: [`Mahatma Gandhi`, `Jawaharlal Nehru`, `B.R. Ambedkar`, `Rabindranath Tagore`], e: `The correct answer is (A) Mahatma Gandhi Explanation: · 'The Story of My Experiments with Truth' is the autobiography of Mohandas K. Gandhi. · It covers his life from early childhood through to 1921. Information Booster: · The book was originally written in Gujarati and later translated into English and other languages. Additional Knowledge: · Jawaharlal Nehru (Option B): Wrote 'The Discovery of India'. · B.R. Ambedkar (Option C): Wrote 'The Annihilation of Caste'. · Rabindranath Tagore (Option D): Wrote 'Gitanjali'.` },
  { s: `General Awareness`, q: `What term refers to the number of individuals living per unit area?`, o: [`Population density`, `Carrying capacity`, `Fertility rate`, `Mortality rate`], e: `The correct answer is (A) Population density Explanation: · Population density is a measurement of population per unit area (e.g., per square kilometer). · It helps in understanding the distribution and concentration of people or organisms in a specific region. Information Booster: · As per the 2011 Census, the population density of India was 382 persons per square km. Additional Knowledge: · Carrying capacity (Option B): The maximum population size an environment can sustain indefinitely. · Fertility rate (Option C): The average number of children born to a woman. · Mortality rate (Option D): The number of deaths in a given population.` },
  { s: `General Awareness`, q: `Which musical instrument is commonly used in Carnatic classical music?`, o: [`Tabla`, `Veena`, `Guitar`, `Piano`], e: `The correct answer is (B) Veena Explanation: · The Saraswati Veena is a prominent string instrument in Carnatic classical music (South India). · Other common instruments in this tradition include the Mridangam, Violin, and Flute. Information Booster: · Unlike Hindustani music where the Sitar is dominant, the Veena remains the primary plucked string instrument in the Carnatic tradition. Additional Knowledge: · Tabla (Option A): Primarily used in Hindustani classical music (North India).` },
  { s: `General Awareness`, q: `The Olympic Games are held every how many years?`, o: [`2`, `3`, `4`, `5`], e: `The correct answer is (C) 4 Explanation: · Both the Summer and Winter Olympic Games are held every four years. · This four-year period is known as an 'Olympiad'. Information Booster: · The modern Olympic Games were inspired by the ancient games held in Olympia, Greece. Additional Knowledge: · While each specific type (Summer/Winter) happens every 4 years, they are staggered so there is an Olympic event every 2 years.` },
  { s: `General Awareness`, q: `Who appoints the Chief Justice of India?`, o: [`Prime Minister`, `President of India`, `Parliament`, `Vice President`], e: `The correct answer is (B) President of India Explanation: · The Chief Justice of India (CJI) and the other judges of the Supreme Court are appointed by the President under clause (2) of Article 124 of the Constitution. · Usually, the senior-most judge of the Supreme Court is appointed as the CJI. Information Booster: · The President also administers the oath of office to the Chief Justice of India. Additional Knowledge: · The appointment is made by the President after consultation with such judges of the Supreme Court and High Courts as he deems necessary (Collegium system).` },
  { s: `General Awareness`, q: `Who is the author of the famous novel "Malgudi Days"?`, o: [`R.K. Narayan`, `Salman Rushdie`, `Vikram Seth`, `Ruskin Bond`], e: `The correct answer is (A) R.K. Narayan Explanation: · 'Malgudi Days' is a collection of short stories by R.K. Narayan published in 1943. · The stories are set in the fictional town of Malgudi in South India. Information Booster: · R.K. Narayan is one of the three most influential early Indian writers in English, along with Mulk Raj Anand and Raja Rao. Additional Knowledge: · Ruskin Bond (Option D): Famous for stories set in the Himalayas, like 'The Blue Umbrella'. · Salman Rushdie (Option B): Famous for 'Midnight's Children'.` },
  { s: `Quantitative Aptitude`, q: `Which number set/sets includes all rational and irrational numbers ?`, o: [`Natural numbers`, `Whole numbers`, `Real numbers`, `Complex numbers`], e: `Given: Number sets involving rational and irrational numbers. Concept Used: The set of Real numbers is formed by combining the set of rational numbers and the set of irrational numbers. Solution: Natural numbers are {1, 2, 3, ...}. Whole numbers are {0, 1, 2, 3, ...}. Complex numbers include real numbers and imaginary numbers. Real numbers include all rational and irrational numbers. So the correct answer is (c)` },
  { s: `Quantitative Aptitude`, q: `A shop offers two successive discounts on a product: the first is 15%, and the second is 10%. What is the single equivalent discount percentage?`, o: [`23.5%`, `24.0%`, `24.5%`, `25.0%`], e: `Given: First discount (D1 ) = 15% Second discount (D2 ) = 10% Formula Used: Single equivalent discount = D1 + D2 - D × D 1 2 100 Solution: 15 × 10 Equivalent discount = 15 + 10 - 100 150 Equivalent discount = 25 - 100 Equivalent discount = 25 - 1.5 = 23.5% So the correct answer is (a)` },
  { s: `Quantitative Aptitude`, q: `In a bag of candies, 55% are red and 26% are blue. What percentage are green?`, o: [`20%`, `19%`, `30%`, `29%`], e: `G iven: Red candies = 55% Blue candies = 26% Formula used: Remaining percentage = 100% - (given percentages) Solution: Green candies = 100 - (55 + 26) = 100 - 81 = 19% Thus, correct answer is 19%.` },
  { s: `Quantitative Aptitude`, q: `In a town, there are 3,600 females for every 3,800 males. What is the sex ratio in this town (number of females per 1000 males)?`, o: [`920`, `940`, `947`, `960`], e: `Given: Females = 3600 Males = 3800 Formula Used: Sex Ratio = Number of Females × 1000 Number of Males Solution: Final Answer: So the correct answer is (c) Given: Formula used: Sex ratio = (Females / Males) × 1000 Solution: Sex ratio = (3600 / 3800) × 1000 = (36 / 38) × 1000 = (18 / 19) × 1000 = 947.37 Thus, sex ratio 947 females per 1000 males.` },
  { s: `Quantitative Aptitude`, q: `A town has a population of 18,000. It increases by 10% in the first year and decreases by 5% in the next year. What is the final population?`, o: [`16,500`, `18,810`, `15,800`, `17,000`], e: `Given: Initial population = 18000 Increase = 10% Decrease = 5% Formula used: Successive change = Initial × (1 + a/100) × (1 - b/100) Solution: After 1st year = 18000 × 1.10 = 19800 After 2nd year = 19800 × 0.95 = 18810 Thus, final population = 18810.` },
  { s: `Quantitative Aptitude`, q: `A vehicle takes 10 hours to travel 600 km. If the speed is increased by 20 km/h, find the new time taken.`, o: [`4.4 hours`, `7.5 hours`, `6 hours`, `7 hours`], e: `Given: Distance = 600 km Time = 10 hours Increase in speed = 20 km/h Formula used: Speed = Distance / Time Time = Distance / New Speed Solution: Original speed = 600 / 10 = 60 km/h New speed = 60 + 20 = 80 km/h New time = 600 / 80 = 7.5 hours Thus, correct option is (b).` },
  { s: `Quantitative Aptitude`, q: `A merchant buys 40 mugs for 2000. He sells 20 of them at 70 each and the remaining at 50 each. What is his profit or loss percentage?`, o: [`8%`, `10%`, `12%`, `20%`], e: `Given: Total mugs = 40 Cost price = 2000 Sold 20 mugs at 70 each Remaining 20 mugs at 50 each Formula used: Profit % = (Profit / Cost Price) × 100 Solution: Total selling price = (20 × 70) + (20 × 50) = 1400 + 1000 = 2400 Profit = 2400 - 2000 = 400 Profit % = (400 / 2000) × 100 = 20% Thus, correct answer is 20% profit.` },
  { s: `Quantitative Aptitude`, q: `What is the selling price if the cost price is 800 and the profit is 25%?`, o: [`650`, `900`, `700`, `1000`], e: `Given: Cost price = 800 Profit = 25% Formula Used: Selling price = Cost price × (1 + prof it ) 100 Solution: Selling price = 800 × (1 + 25/100) = 800 × 1.25 = 1000 Thus, correct answer is 1000.` },
  { s: `Quantitative Aptitude`, q: `The average weight of 6 students is 45 kg. If one more student weighing 75 kg joins, what is the new average weight?`, o: [`51.40 kg`, `59 kg`, `49.29 kg`, `54.20 kg`], e: `Given: Average weight of 6 students = 45 kg Weight of one new student = 75 kg Formula used: Total = Average × Number New average = (Old total + New value) / Total number Solution: Old total = 6 × 45 = 270 New total = 270 + 75 = 345 New average = 345 / 7 = 49.29 kg Thus, correct answer is 49.29 kg.` },
  { s: `Quantitative Aptitude`, q: `X and Y can complete a work in 12 days. Y alone can do it in 20 days. In how many days will X alone complete the work?`, o: [`25 days`, `30 days`, `35 days`, `40 days`], e: `Given: X and Y together complete work in 12 days Y alone completes work in 20 days Formula used: Work rate = 1/time X's work = (X + Y) - Y Solution: (X + Y) one day work = 1/12 Y one day work = 1/20 X one day work = 1/12 - 1/20 = (5 - 3) / 60 = 2/60 = 1/30 Time taken by X = 30 days Thus, correct option is (b).` },
  { s: `Quantitative Aptitude`, q: `A bakery uses 36 kilograms of flour each day. On Monday, it used only 1/3 of the daily amount. On Tuesday, it used 20% more than it did on Monday. How much flour was used in total over the two days?`, o: [`26.40 kilograms`, `28.50 kilograms`, `26.04 kilograms`, `25.50 kilograms`], e: `Given: Daily flour = 36 kg Monday = 1/3 of daily Tuesday = 20% more than Monday Concept Used: Percentage and basic arithmetic Formula Used: Percentage increase = Original × (1 + %/100) Solution: Monday flour = 36 × 1/3 = 12 kg Tuesday flour = 12 × 1.2 = 14.4 kg Total flour used = 12 + 14.4 = 26.4 kg Thus, correct answer is 26.4 kg.` },
  { s: `Quantitative Aptitude`, q: `How many natural numbers are there between 13² and 17²?`, o: [`118`, `119`, `123`, `115`], e: `Given: Numbers between 13² and 17² Concept Used: Difference of squares and counting integers Formula Used: Number of integers between two numbers = Larger - Smaller - 1 Solution: 13² = 169 17² = 289 Numbers between = 289 - 169 - 1 = 119 Thus, correct answer is 119.` },
  { s: `Quantitative Aptitude`, q: `The average of a set of 20 numbers is 70. If one number, 30, is replaced by 40, what is the new average?`, o: [`70.5`, `42.5`, `43.5`, `40`], e: `Given: Number of observations = 20 Average = 70 One number 30 is replaced by 40 Concept Used: Average (sum adjustment method) Formula Used: Total = Average × Number Solution: Old total = 20 × 70 = 1400 Increase in sum = 40 - 30 = 10 New total = 1400 + 10 = 1410 New average = 1410 / 20 = 70.5 Thus, correct answer is 70.5` },
  { s: `Quantitative Aptitude`, q: `A triangle has sides 8 cm, 15 cm, and 17 cm. What type of triangle is this?`, o: [`Acute`, `Obtuse`, `Right-angled`, `Equilateral`], e: `Given: Sides of triangle = 8 cm, 15 cm, 17 cm Formula used: Pythagoras theorem: (largest side)² = (other side)² + (other side)² Solution: A triangle has sides 8 cm, 15 cm, and 17 cm. What type of triangle is this? Largest side = 17 17² = 289 8² + 15² = 64 + 225 = 289 Since both are equal, the triangle is a right-angled triangle Thus, correct answer is Right-angled triangle.` },
  { s: `Quantitative Aptitude`, q: `A submarine was at a depth of -80 meters. It first ascended 30 meters and then descended 10 meters. What is its final position relative to sea level?`, o: [`-60 meters`, `-65 meters`, `+25 meters`, `-20 meters`], e: `Given: Initial depth = -80 meters Ascends = 30 meters Descends = 10 meters Formula used: Final position = Initial position + upward movement - downward movement Solution: Final position = -80 + 30 - 10 = -60 meters Thus, correct option is (a).` },
  { s: `Quantitative Aptitude`, q: `A solid cylinder is melted and recast into smaller cylinders of the same height but half the radius. How many smaller cylinders can be made?`, o: [`3`, `6`, `4`, `12`], e: `Given: Radius of big cylinder = R Radius of small cylinder = R/2 Height same Formula used: Volume of cylinder = r²h Solution: Volume of big cylinder = R²h Volume of small cylinder = (R/2)²h = R²h / 4 Number of small cylinders = (R²h) ÷ (R²h / 4) = 4 Thus, correct option is (c).` },
  { s: `Quantitative Aptitude`, q: `A recipe needs 8 cups of sugar to make 36 cookies. How many cups of sugar are needed to make 45 cookies in the same proportion?`, o: [`5 cups`, `6 cups`, `7 cups`, `10 cups`], e: `Given: 8 cups of sugar are used to make 36 cookies We need sugar for 45 cookies Solution: If 36 cookies require 8 cups, then 1 cookie requires = 8/36 cups So, for 45 cookies: Sugar needed = (8/36) × 45 Simplify: = (2/9) × 45 = 2 × 5 = 10 cups Thus, correct answer is 10 cups.` },
  { s: `Quantitative Aptitude`, q: `From a point P, a tangent is drawn to a circle with center O. The radius is 60 cm, and the distance from O to P is 61 cm. What is the length of the tangent?`, o: [`12 cm`, `11 cm`, `18 cm`, `20 cm`], e: `Given: Radius (OP to circle) = 60 cm Distance OP = 61 cm Concept Used: Pythagoras theorem (tangent radius at point of contact) Formula Used: Tangent length² = OP² - radius² Solution: Tangent length² = 61² - 60² = 3721 - 3600 = 121 Tangent length = 121 = 11 cm Thus, correct answer is 11 cm.` },
  { s: `Quantitative Aptitude`, q: `A train travels 3000 km in 5 hours. What is its speed?`, o: [`166 m/s`, `166.67 m/s`, `160 m/s`, `176.67m/s`], e: `Given: Distance = 3000 km Time = 5 hours Formula used: Speed = Distance / Time Solution: Speed = 3000 ÷ 5 = 600 km/h Convert into m/s: 600 × (5/18) = 166.67 m/s Thus, correct answer is 166.67 m/s.` },
  { s: `Quantitative Aptitude`, q: `A cone and a cylinder have the same radius and height. The ratio of their total surface area is:`, o: [`1:2`, `1:3`, `2:3`, `3:4`], e: `Given: Cone and cylinder have same radius (r) and height (h) Formula used: Total surface area of cone = r(l + r) Total surface area of cylinder = 2r(h + r) Solution: For same r and h, take l = h (standard exam assumption) Cone TSA = r(h + r) Cylinder TSA = 2r(h + r) Ratio = r(h + r) : 2r(h + r) = 1 : 2 Thus, correct answer is 1 : 2.` },
  { s: `Quantitative Aptitude`, q: `A dealer allows a 25% discount on the marked price and still makes a profit of 20%. If the cost price of the article is 2000, what is the marked price?`, o: [`1,900`, `2,000`, `3,200`, `2,200`], e: `Given: Cost price = 2000 Discount = 25% Profit = 20% Formula used: Selling price = Cost price × (1 + profit/100) Marked price = Selling price / (1 - discount/100) Solution: Selling price = 2000 × 1.2 = 2400 Marked price = 2400/0.75 = 3200 Thus, correct answer is 3200.` },
  { s: `Quantitative Aptitude`, q: `If the volume of a rectangular parallelepiped is 750 cm³ and its base area is 100 cm², what is its height?`, o: [`7.5 cm`, `8 cm`, `9.5 cm`, `10 cm`], e: `Given: Volume = 750 cm³ Base area = 100 cm² Formula used: Volume = Base area × Height Solution: Height = Volume/Base area = 750/100 = 7.5 cm Thus, correct answer is 7.5 cm` },
  { s: `Quantitative Aptitude`, q: `What is 137/11 as a mixed number? 5`, o: [`12`, `11`, `12`, `11`], e: `Given: Fraction: 137 11 Formula Used: Mixed Number = Quotient(Remainder/Divisor) Solution: Divide 137 by 11. 137 ÷11 = 12 with a remainder of 5. The quotient is 12, the remainder is 5, and the divisor is 11. 5 Therefore, the mixed number is 12 . 11 So the correct answer is (a).` },
  { s: `Quantitative Aptitude`, q: `A sum fetches 7,200 as interest in 3 years at 12% per annum. What is the principal?`, o: [`12,000`, `14,000`, `15,000`, `20,000`], e: `Given: Simple Interest = 7200 Time = 3 years Rate = 12% per annum Formula Used: SI = (P × R × T)/ 100 Solution: 7200 = (P × 12 × 3) / 100 7200 = (36P) / 100 7200 = 0.36P P = 7200 / 0.36 = 20000 Thus, correct answer is 20000.` },
  { s: `Quantitative Aptitude`, q: `P and Q complete a work in 24 days. Q alone takes 48 days. In how many days will P alone complete the work?`, o: [`48 days`, `50 days`, `42 days`, `54 days`], e: `Given: P + Q complete work in 24 days Q alone completes work in 48 days F ormulaU sed : W orkrate = 1 time Solution : 1 (P + Q)onedaywork = 24 Qonedaywork = 1 48 11 P onedaywork = - 24 48 2-1 = 48 1 = T imetakenbyP = 48 daysT hus, correctansweris48days. 48 Formula Used : 1 Work rate = time Solution : 1 (P + Q) one day work = 24 1 Q one day work = 48 11 P one day work = - 24 48 = 2-1 48 1 = Time taken by P = 48 days 48 Thus, correct answer is 48 days.` },
  { s: `English Language`, q: `Fill in the blank with most appropriate option: It was the __ match of the entire tournament.`, o: [`exciting`, `more exciting`, `much exciting`, `most exciting`], e: `Explanation The correct option to fill in the blank is (d) most exciting. In this sentence, the definite article 'the' precedes the blank and the context compares one match against the 'entire tournament' (more than two matches). This structure necessitates the use of a superlative adjective to indicate the highest degree of a quality. Grammatical Rule used When comparing more than two things or referring to the highest degree of a quality within a group, the superlative degree is used. For multi- syllabic adjectives like 'exciting', the superlative is formed by adding 'most' before the adjective. The superlative is also typically preceded by the definite article 'the'. Example This is the most beautiful painting in the gallery. Information Booster Positive degree: exciting; Comparative de` },
  { s: `English Language`, q: `Arrange the passage correctly: (1) He secured the tent pegs firmly into the ground. (2) He selected a flat patch of ground at the campsite. (3) He unrolled the tent and laid out all the parts. (4) He assembled the poles and raised the tent into shape.`, o: [`2-3-4-1`, `3-2-4-1`, `2-4-3-1`, `3-4-2-1`], e: `Explanation Option (a) is the correct order of the given sentences. The logical sequence of pitching a tent involves preparation before execution: Sentence (2) is the opening statement as it describes selecting the location, which is the first step. Sentence (3) follows as it involves unpacking and laying out the materials at the selected site. Sentence (4) describes the next physical step of assembling the structure and raising it. Sentence (1) is the concluding step, describing the final securing of the tent to the ground once it has been raised. So the correct answer is (a)` },
  { s: `English Language`, q: `Fill in the blank with most appropriate tense: When she was young, she __ to swim in the river every summer.`, o: [`used to`, `use to`, `was used to`, `is used to`], e: `Explanation The correct option to fill in the blank is (a) used to. This expression is used to describe habits or states in the past that no longer exist. The phrase 'When she was young' clearly indicates a past timeframe, making 'used to' the appropriate choice to denote her past routine. Example I used to play cricket when I was in school. Why other options are incorrect Option B (use to): This is grammatically incorrect in an affirmative sentence; 'use to' is only used in negative or interrogative sentences with 'did' (e.g., Did she use to?). Option C (was used to): This means 'to be accustomed to' and is followed by a gerund (V1+ing). It does not fit the structure 'to swim'. Option D (is used to): This refers to a present habit of being accustomed to something and is also followed by a` },
  { s: `English Language`, q: `Fill in the blank with most appropriate option: She is a woman __ dedication is truly inspiring.`, o: [`who`, `whom`, `which`, `whose`], e: `Explanation The correct option to fill in the blank is (d) whose. In this sentence, we need a relative pronoun that shows possession or a relationship between the 'woman' and her 'dedication'. 'Whose' functions as a possessive relative pronoun for people. Example The boy whose bag was lost is crying. Why other options are incorrect Option A (who): Used as a subject pronoun for people (e.g., the woman who is dedicated). Option B (whom): Used as an object pronoun for people. Option C (which): Used for things or animals, not for people in this context. Information Booster 'Whose' is the only relative pronoun that can be used to indicate possession for both living and non-living things in many contexts, though primarily used for persons in formal English. So the correct answer is (d)` },
  { s: `English Language`, q: `Which word is spelled correctly?`, o: [`Acommodate`, `Accommodate`, `Accomodate`, `Accommoddate`], e: `Explanation Option (b) is the correctly spelt word. Correct Spelling The correct spelling is: "Accommodate", which means to provide lodging or sufficient space for someone or something; or to fit in with the wishes or needs of others. ( / ) Example The hotel can accommodate up to five hundred guests. Information Booster 'Accommodate' is a verb. A common mnemonic to remember the spelling is that it has 'two Cs and two Ms', like a large room accommodating two Cots and two Mattresses. So the correct answer is (b)` },
  { s: `English Language`, q: `Arrange the passage correctly: (1) Pour hot water over the powder and stir until dissolved. (2) Add milk or sugar according to your preference. (3) Measure one teaspoon of coffee powder into the cup. (4) Serve hot and enjoy your freshly made coffee.`, o: [`3-1-2-4`, `1-3-2-4`, `3-2-1-4`, `1-2-3-4`], e: `Explanation Option (a) is the correct order of the given sentences. The logical flow of making coffee is as follows: Sentence (3) is the first step as you must put the coffee powder in the cup before adding liquid. Sentence (1) follows as it describes adding the hot water and stirring the powder. Sentence (2) is the next logical step, where you customize the drink with milk or sugar. Sentence (4) is the concluding statement, indicating the coffee is ready to be served and enjoyed. So the correct answer is (a)` },
  { s: `English Language`, q: `Identify the synonym of 'Wistful':`, o: [`Melancholic`, `Cheerful`, `Elated`, `Composed`], e: `Explanation The correct synonym of the given word is (a) Melancholic. Wistful Having or showing a feeling of vague or regretful longing. It often refers to thinking sadly about something you would like to have or something in the past. ( /) Example She gave a wistful smile as she looked at her old childhood photographs. Melancholic Feeling or expressing pensive sadness; having a feeling of melancholy. It aligns closely with the sad longing implied by 'wistful'. () Example The rainy weather always makes him feel melancholic. Synonyms Pensive, Yearning, Forlorn, Nostalgic. Antonyms Cheerful, Joyful, Happy, Contented. Meanings of other options Cheerful: Noticeably happy and optimistic. () Elated: Make someone ecstatically happy. (/ ) Composed: Having one's feelings and expression under contro` },
  { s: `English Language`, q: `Fill in the blank with most appropriate option: The coach insisted __ strict training every single day.`, o: [`at`, `about`, `in`, `on`], e: `Explanation The correct option to fill in the blank is (d) on. This is a case of a fixed prepositional phrase. The verb 'insist' is traditionally followed by the preposition 'on' (or 'upon') when followed by a noun or a gerund. ( ) Example He insisted on paying for the dinner. Why other options are incorrect Option A (at): 'Insist at' is not a standard English idiom. Option B (about): While we can talk 'about' something, we 'insist on' something. Option C (in): 'Insist in' is grammatically incorrect in this context. Information Booster Certain verbs always take specific prepositions. Examples: Depend on, Rely on, Congratulate on, Insist on. So the correct answer is (d)` },
  { s: `English Language`, q: `Choose the correct one-word substitution for: "A person who studies celestial bodies and outer space."`, o: [`Astrologer`, `Geologist`, `Astronomer`, `Meteorologist`], e: `Explanation The correct one-word for the given group of words is (c) Astronomer. An astronomer is a scientist who focuses on the study of the universe, including stars, planets, and galaxies. () Example The astronomer pointed the telescope toward the distant nebula to gather data. Meanings of other options Astrologer: A person who uses the movements of celestial bodies to interpret human affairs and terrestrial events. () Geologist: An expert who studies the Earth's physical structure, substance, and history. () Meteorologist: An expert in or student of meteorology; a weather forecaster. ( ) So the correct answer is (c)` },
  { s: `English Language`, q: `Choose the correct one-word substitution for: "The art of producing beautiful and decorative handwriting."`, o: [`Typography`, `Calligraphy`, `Cartography`, `Lithography`], e: `Explanation The correct one-word for the given group of words is (b) Calligraphy. Calligraphy is the design and execution of lettering with a pen, ink brush, or other writing instrument. () Example The wedding invitations were written in elegant calligraphy. Meanings of other options Typography: The style and appearance of printed matter; the art of arranging type. ( ) Cartography: The science or practice of drawing maps. () Lithography: A method of printing from a flat surface treated so as to repel the ink except where it is required for printing. () So the correct answer is (b)` },
  { s: `English Language`, q: `Identify the synonym of 'Knavery':`, o: [`Loyalty`, `Trickery`, `Devotion`, `Sincerity`], e: `Explanation The correct synonym of the given word is (b) Trickery. Knavery Unprincipled, untrustworthy, or dishonest dealing; the act of a rogue or a scoundrel. (/) Example The politician's knavery was eventually exposed by the investigative journalist. Trickery The use of dishonest methods to trick people in order to achieve something. This is a direct synonym for the deceitful nature of knavery. (-) Example He used trickery to convince the villagers to sell their land. Synonyms Deceit, Duplicity, Dishonesty, Rogueishness. Antonyms Honesty, Integrity, Sincerity, Probity. Meanings of other options Loyalty: The quality of being loyal to someone or something. () Devotion: Love, loyalty, or enthusiasm for a person, activity, or cause. (/) Sincerity: The quality of being free from pretense, de` },
  { s: `English Language`, q: `Choose the correct meaning of the given idiom/phrase from the options: "Steal someone's thunder"`, o: [`To cause a loud disturbance in public`, `To take credit for someone else's achievement`, `To become very angry suddenly`, `To act without thinking of consequences`], e: `Explanation Option (b) is the correct meaning of the given idiom. Steal someone's thunder To take the attention or praise away from someone else's accomplishments or to do what they were going to do before they can do it, thus lessening the impact. ( ) Example I was about to announce my promotion when my brother stole my thunder by announcing his engagement. Other related idioms Take the wind out of someone's sails: To make someone feel less confident. Ride someone's coattails: To benefit from someone else's success. So the correct answer is (b)` },
  { s: `English Language`, q: `Find the part of the sentence that contains an error: She entered inside (1) / the examination hall (2) / and quietly (3) / took her seat (4).`, o: [`She entered inside (1)`, `the examination hall (2)`, `and quietly (3)`, `took her seat. (4)`], e: `Explanation Option (a) contains an error. The use of 'inside' after 'entered' is redundant because the verb 'enter' itself means 'to go or come inside'. Therefore, using 'inside' creates a tautology. Grammatical Rule used Redundancy or Superfluous expressions should be avoided. The verb 'enter' does not take the preposition 'into' or the adverb 'inside' when referring to moving into a physical space or building. Example Incorrect: He entered into the room. Correct: He entered the room. Information Booster 'Enter into' is used only in figurative contexts, such as 'entering into an agreement' or 'entering into an alliance'. So the correct answer is (a)` },
  { s: `English Language`, q: `Find the part of the sentence that contains an error: He ran very quick (1) / across the field (2) / to catch (3) / the ball (4).`, o: [`He ran very quick (1)`, `across the field (2)`, `to catch (3)`, `the ball. (4)`], e: `Explanation Option (a) contains an error. The word 'quick' is an adjective, but in this sentence, it is modifying the verb 'ran'. To modify a verb, we must use an adverb. Therefore, 'quick' should be replaced by 'quickly'. Grammatical Rule used Adjectives describe nouns or pronouns, whereas adverbs are used to modify verbs, adjectives, or other adverbs. Most adverbs are formed by adding '-ly' to the adjective form. Example Incorrect: She sings beautiful. Correct: She sings beautifully. So the correct answer is (a)` },
  { s: `English Language`, q: `Arrange the passage correctly: (1) She folded the letter neatly and slipped it into an envelope. (2) She sat at her desk and began to write the letter carefully. (3) She handed the sealed envelope to the postal clerk. (4) She sealed the envelope and wrote the recipient's address on it.`, o: [`2-1-4-3`, `1-2-4-3`, `2-4-1-3`, `1-4-2-3`], e: `Explanation Option (a) is the correct order of the given sentences. The logical steps of sending a letter are as follows: Sentence (2) is the starting point, where she begins writing the letter. Sentence (1) describes the next step: folding the written letter and putting it in an envelope. Sentence (4) follows, describing sealing the envelope and addressing it. Sentence (3) is the final action, delivering the finished envelope to the post office. So the correct answer is (a)` },
  { s: `English Language`, q: `The phrase "The wind whispered through the trees" is an example of __.`, o: [`simile`, `metaphor`, `personification`, `alliteration`], e: `Explanation The correct option is (c) personification. Personification is a figure of speech where human qualities or actions are attributed to non-human things or abstract ideas. In this phrase, 'whispering' is a human action attributed to 'the wind'. Meanings of other options Simile: A comparison between two different things using 'like' or 'as' (e.g., as cold as ice). Metaphor: A direct comparison where one thing is said to be another (e.g., the snow is a white blanket). Alliteration: The occurrence of the same letter or sound at the beginning of adjacent or closely connected words (e.g., sweet birds sang). So the correct answer is (c)` },
  { s: `English Language`, q: `Identify the antonym of "Celebrated":`, o: [`Renowned`, `Distinguished`, `Obscure`, `Eminent`], e: `Explanation The correct antonym of the given word is (c) Obscure. Celebrated Well known, famous, and respected. It refers to someone or something that has attained public acclaim. (/) Example He is a celebrated author who has won many prestigious awards. Obscure Not discovered or known about; uncertain. In the context of fame, it means someone who is unknown or not famous. (/) Example The museum displays works by obscure artists as well as famous ones. Synonyms Famous, Renowned, Eminent, Illustrious. Antonyms Unknown, Obscure, Inglorious, Unsung. Meanings of other options Renowned: Known or talked about by many people; famous. () Distinguished: Successful, authoritative, and commanding great respect. () Eminent: Famous and respected within a particular sphere. () So the correct answer is (` },
  { s: `English Language`, q: `Arrange the passage correctly: (1) She checked in at the counter and collected her boarding pass. (2) She arrived at the airport well ahead of her departure time. (3) She boarded the aircraft and found her seat comfortably. (4) She passed through security and proceeded to the departure gate.`, o: [`2-1-4-3`, `1-2-3-4`, `2-4-1-3`, `1-4-2-3`], e: `Explanation Option (a) is the correct order of the given sentences. The chronological sequence of air travel procedures is: Sentence (2) is the logical start, showing her arrival at the airport. Sentence (1) describes the first mandatory task after arrival: checking in and getting the pass. Sentence (4) follows, representing the mandatory security screening and heading to the gate. Sentence (3) is the final step in this sequence: getting on the plane and finding her seat. So the correct answer is (a)` },
  { s: `English Language`, q: `Find the part of the sentence that contains an error: He is a (1) / honest and hardworking person (2) / who never (3) / gives up easily (4).`, o: [`He is a (1)`, `honest and hardworking person (2)`, `who never (3)`, `gives up easily. (4)`], e: `Explanation Option (a) contains an error. The article 'a' should be replaced by 'an'. Although the word 'honest' starts with the consonant 'h', the 'h' is silent, and the word begins with a vowel sound (O-nest). Grammatical Rule used The article 'an' is used before words that begin with a vowel sound, regardless of whether the first letter is a vowel or a consonant. The article 'a' is used before words that begin with a consonant sound. Example An hour, An MBA, A university (starts with 'y' sound), A European. So the correct answer is (a)` },
  { s: `English Language`, q: `Find the part of the sentence that contains an error: She spoke very confident (1) / during the interview (2) / and impressed (3) / the entire panel (4).`, o: [`She spoke very confident (1)`, `during the interview (2)`, `and impressed (3)`, `the entire panel. (4)`], e: `Explanation Option (a) contains an error. The adjective 'confident' is used incorrectly here to modify the verb 'spoke'. We must use the adverbial form 'confidently' to describe how she spoke. Grammatical Rule used An adverb is required to modify a verb. Adjectives modify nouns (e.g., She is confident), while adverbs modify verbs (e.g., She spoke confidently). Example Incorrect: He drives careful. Correct: He drives carefully. So the correct answer is (a)` },
  { s: `English Language`, q: `Pick the correctly spelled word:`, o: [`Nesessary`, `Nessesary`, `Necessary`, `Necessery`], e: `Explanation Option (c) is the correctly spelt word. Correct Spelling The correct spelling is: "Necessary", which means required to be done, achieved, or present; needed to be done. () Example It is necessary to wear a helmet while riding a bike. Information Booster 'Necessary' is an adjective. A mnemonic to remember it is: A shirt has one Collar and two Sleeves (one 'c' and two 's'). So the correct answer is (c)` },
  { s: `English Language`, q: `Identify the antonym of "Vivacious":`, o: [`Spirited`, `Animated`, `Dull`, `Vibrant`], e: `Explanation The correct antonym of the given word is (c) Dull. Vivacious Attractively lively and animated (typically used of a woman). It suggests a high-spirited and energetic personality. (/ ) Example Her vivacious personality made her the center of attention at every party. Dull Lacking interest or excitement; boring. As an antonym to vivacious, it refers to someone lacking energy or spark. (/) Example The lecture was so dull that half the students fell asleep. Synonyms Animated, Spirited, Bubbling, Effervescent. Antonyms Dull, Listless, Languid, Spiritless. Meanings of other options Spirited: Full of energy, enthusiasm, and determination. () Animated: Full of life or excitement; lively. (/) Vibrant: Full of energy and life. () So the correct answer is (c)` },
  { s: `English Language`, q: `Find the part of the sentence that contains an error: The committee (1) / have decided unanimously (2) / that the annual event (3) / will be postponed (4).`, o: [`The committee (1)`, `have decided unanimously (2)`, `that the annual event (3)`, `will be postponed. (4)`], e: `Explanation Option (b) contains an error. The plural verb 'have' should be replaced by the singular verb 'has'. This is because the collective noun 'committee' is acting as a single unit here. Grammatical Rule used Collective nouns (like committee, jury, team) take a singular verb when the group is acting as a single entity or is unanimous in its decision. They take a plural verb only when the members are acting individually or are divided in opinion. Example The jury has reached a verdict (unanimous). The jury are divided in their opinions (individual actions). So the correct answer is (b)` },
  { s: `English Language`, q: `Choose the correct meaning of the given idiom/phrase from the options: "Once in a blue moon"`, o: [`During the night only`, `On every full moon night`, `Very rarely`, `At a specific time each month`], e: `Explanation Option (c) is the correct meaning of the given idiom. Once in a blue moon An event that happens very infrequently or rarely. The term refers to the rare occurrence of a second full moon in a single calendar month. ( / ) Example Since he moved to the city, he visits his hometown only once in a blue moon. Other related idioms Seldom or never: Almost never. Hardly ever: Very rarely. So the correct answer is (c)` },
  { s: `English Language`, q: `Arrange to form a meaningful paragraph: (1) The manager welcomed everyone and began the presentation. (2) The team members took their seats around the table. (3) The meeting was adjourned after all points were discussed. (4) The staff gathered in the conference room.`, o: [`4-2-1-3`, `2-4-1-3`, `1-4-2-3`, `4-1-2-3`], e: `Explanation Option (a) is the correct order of the given sentences. The chronological flow of a business meeting is as follows: Sentence (4) is the opening action, where everyone arrives at the location. Sentence (2) follows logically, as people sit down once they have gathered. Sentence (1) describes the start of the formal proceedings by the manager. Sentence (3) is the natural conclusion, stating the meeting ended (adjourned). So the correct answer is (a)` }
];

if (RAW.length !== 100) { console.error(`Expected 100 questions, got ${RAW.length}`); process.exit(1); }

async function seed() {
  console.log('Connecting to MongoDB...');
  await mongoose.connect(MONGO_URI);
  console.log('Connected.');

  let category = await ExamCategory.findOne({ name: 'Central', type: 'Central' });
  if (!category) {
    category = await ExamCategory.create({ name: 'Central', type: 'Central', description: 'Central government competitive exams' });
  }

  let exam = await Exam.findOne({ code: 'SSC-SSP-MAT' });
  if (!exam) {
    exam = await Exam.create({
      category: category._id,
      name: 'SSC Selection Post (Matriculation Level)',
      code: 'SSC-SSP-MAT',
      description: 'Staff Selection Commission - Selection Post (Matriculation Level)',
      isActive: true
    });
  }

  const PATTERN_TITLE = 'SSC Selection Post (Matriculation Level)';
  let pattern = await ExamPattern.findOne({ exam: exam._id, title: PATTERN_TITLE });
  if (!pattern) {
    pattern = await ExamPattern.create({
      exam: exam._id, title: PATTERN_TITLE, duration: 60, totalMarks: 200, negativeMarking: 0.5,
      sections: [
        { name: REA, totalQuestions: 25, marksPerQuestion: 2, negativePerQuestion: 0.5 },
        { name: GA,  totalQuestions: 25, marksPerQuestion: 2, negativePerQuestion: 0.5 },
        { name: QA,  totalQuestions: 25, marksPerQuestion: 2, negativePerQuestion: 0.5 },
        { name: ENG, totalQuestions: 25, marksPerQuestion: 2, negativePerQuestion: 0.5 }
      ]
    });
  }

  const TEST_TITLE = 'SSC Selection Post (Matriculation) - 25 July 2025 Shift-1 [Similar Paper]';
  await PracticeTest.deleteMany({ examPattern: pattern._id, title: TEST_TITLE });

  const questions = RAW.map((r, i) => ({
    questionText: r.q,
    questionImage: '',
    options: r.o,
    optionImages: ['', '', '', ''],
    correctAnswerIndex: KEY[i] - 1,
    explanation: r.e || '',
    section: r.s,
    tags: ['SSC', 'Selection Post', 'Phase XIII', 'Matriculation', 'PYQ', '2025', 'Similar Paper'],
    difficulty: 'medium'
  }));

  const test = await PracticeTest.create({
    examPattern: pattern._id, title: TEST_TITLE, totalMarks: 200, duration: 60,
    accessLevel: 'FREE', isPYQ: true, pyqYear: 2025, pyqShift: '1',
    pyqExamName: 'SSC Selection Post Phase XIII (Matriculation) - Similar Paper', questions
  });
  console.log(`Created PYQ PracticeTest: ${test._id} (${test.questions.length} questions)`);

  await mongoose.disconnect();
  console.log('Done.');
}

seed().catch(err => { console.error('Seed failed:', err); process.exit(1); });
